func New(config ...Config) fiber.Handler {

	cfg := configDefault(config...)

	return func(c fiber.Ctx) error {

		if cfg.Next != nil && cfg.Next(c) {
			return c.Next()
		}

		rid := c.Get(cfg.Header)
		if rid == "" {
			rid = cfg.Generator()
		}

		c.Set(cfg.Header, rid)

		c.Locals(requestIDKey, rid)

		return c.Next()
	}
}
